python3 << 'PY'
import re
from html.parser import HTMLParser
from pathlib import Path

class TextExtractor(HTMLParser):
    SKIP = {"script", "style", "head"}
    BREAKS = {"p", "br", "div", "tr", "li", "h1", "h2", "h3", "h4", "h5", "h6", "section"}

    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.parts = []
        self.skip_depth = 0

    def handle_starttag(self, tag, attrs):
        if tag in self.SKIP:
            self.skip_depth += 1
        if tag in self.BREAKS:
            self.parts.append("\n")

    def handle_endtag(self, tag):
        if tag in self.SKIP and self.skip_depth > 0:
            self.skip_depth -= 1
        if tag in self.BREAKS:
            self.parts.append("\n")

    def handle_data(self, data):
        if self.skip_depth == 0:
            self.parts.append(data)

def normalize(html):
    p = TextExtractor()
    p.feed(html)
    raw = "".join(p.parts)
    # Mirror zapcrp_normalize_whitespace: collapse runs of whitespace in each
    # paragraph, drop empty paragraphs, join with blank lines.
    paragraphs = []
    for para in re.split(r"\n\s*\n", raw):
        collapsed = re.sub(r"\s+", " ", para).strip()
        if collapsed:
            paragraphs.append(collapsed)
    return "\n\n".join(paragraphs)

for src, dst in (
    ("Tools/apck/test_fixtures/epic_progress_note.html",     "Tools/apck/test_fixtures/epic_initial.txt"),
    ("Tools/apck/test_fixtures/epic_geriatric_consult.html", "Tools/apck/test_fixtures/epic_geriatric.txt"),
):
    html = Path(src).read_text(encoding="utf-8")
    text = normalize(html)
    Path(dst).write_text(text, encoding="utf-8")
    print(f"{dst}: {len(text)} chars, {text.count(chr(10)) + 1} lines")

